# BudgetSync Application
# This system is designed to facilitate collaborative budgeting among multiple users.

class User:
    def __init__(self, user_id, name, email):
        self.user_id = user_id
        self.name = name
        self.email = email

class Transaction:
    def __init__(self, transaction_id, user_id, amount, description, transaction_type):
        self.transaction_id = transaction_id
        self.user_id = user_id
        self.amount = amount
        self.description = description
        self.transaction_type = transaction_type  # 'income' or 'expense'

