    def __init__(self, budget_id, user_ids, goal_amount, current_amount=0):
        self.budget_id = budget_id
        self.user_ids = user_ids
        self.goal_amount = goal_amount
        self.current_amount = current_amount
        self.transactions = []

    def add_transaction(self, transaction):
        self.transactions.append(transaction)
        if transaction.transaction_type == 'income':
            self.current_amount += transaction.amount
        elif transaction.transaction_type == 'expense':
            self.current_amount -= transaction.amount

    def get_budget_status(self):
        return {
            'budget_id': self.budget_id,
            'goal_amount': self.goal_amount,
            'current_amount': self.current_amount,
            'remaining_amount': self.goal_amount - self.current_amount
        }

class BudgetSync:
    def __init__(self):
        self.users = {}
        self.budgets = {}

    def add_user(self, user_id, name, email):
        self.users[user_id] = User(user_id, name, email)

    def create_budget(self, budget_id, user_ids, goal_amount):
        self.budgets[budget_id] = Budget(budget_id, user_ids, goal_amount)

